import{c as t,Q as a,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Choosing a surface","description":"Decision tree for HavenBot vs MCP vs OpenClaw vs Hosted Checkout.","frontmatter":{"title":"Choosing a surface","description":"Decision tree for HavenBot vs MCP vs OpenClaw vs Hosted Checkout."},"headers":[],"relativePath":"get-started/choosing-a-surface.md","filePath":"get-started/choosing-a-surface.md","lastUpdated":1780245214000}'),s={name:"get-started/choosing-a-surface.md"};function r(d,e,i,l,h,c){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="choosing-a-surface" tabindex="-1">Choosing a surface <a class="header-anchor" href="#choosing-a-surface" aria-label="Permalink to &quot;Choosing a surface&quot;">​</a></h1><p>MuHaven is architected around four agentic surfaces that share the same SDK and the same policy gate. Three are live today — <strong>HavenBot</strong>, <strong><code>@muhaven/mcp</code></strong>, and the <strong>Telegram bot</strong> — while the <strong>OpenClaw skill</strong> and <strong>Hosted Checkout</strong> are in development. You don&#39;t have to pick one — most users run two or three side by side. But there&#39;s a natural starting surface for any given context.</p><h2 id="quick-chooser" tabindex="-1">Quick chooser <a class="header-anchor" href="#quick-chooser" aria-label="Permalink to &quot;Quick chooser&quot;">​</a></h2><table tabindex="0"><thead><tr><th>If you…</th><th>Start with</th><th>Why</th></tr></thead><tbody><tr><td>Are brand-new and want a guided UX</td><td><a href="/havenbot/overview"><strong>HavenBot</strong></a></td><td>Zero install, in-dashboard onboarding wizard, click-confirmable previews.</td></tr><tr><td>Already use Claude Code / Desktop / Cursor daily</td><td><a href="/mcp/overview"><strong><code>@muhaven/mcp</code></strong></a></td><td>Bring your own LLM; sit MuHaven next to your other MCP servers.</td></tr><tr><td>Live on your phone and want one-tap actions</td><td><a href="/openclaw/overview"><strong>OpenClaw + Telegram</strong></a></td><td>Phone-first UX, three confirmation tiers, no laptop needed.</td></tr><tr><td>Are an issuer minting a one-off buy URL for a non-customer</td><td><a href="/checkout/overview"><strong>Hosted Checkout</strong></a></td><td>Buyer doesn&#39;t need an account — provisions one via passkey at checkout.</td></tr></tbody></table><h2 id="decision-tree" tabindex="-1">Decision tree <a class="header-anchor" href="#decision-tree" aria-label="Permalink to &quot;Decision tree&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌─ &quot;I want to drive everything from my phone.&quot;</span></span>
<span class="line"><span>                │  → OpenClaw + Telegram bot (chat with @muhaven_bot)</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>                ├─ &quot;I want to be the LLM owner. I already use Claude Code.&quot;</span></span>
<span class="line"><span>                │  → @muhaven/mcp (install in your host)</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>Who are you? ───┤</span></span>
<span class="line"><span>                ├─ &quot;I want to send a pay link to someone who doesn&#39;t have a MuHaven account.&quot;</span></span>
<span class="line"><span>                │  → Hosted Checkout (issuer-side create-link tool)</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>                └─ &quot;I just want to use MuHaven.&quot;</span></span>
<span class="line"><span>                   → HavenBot in the dashboard (default)</span></span></code></pre></div><h2 id="feature-parity-matrix" tabindex="-1">Feature parity matrix <a class="header-anchor" href="#feature-parity-matrix" aria-label="Permalink to &quot;Feature parity matrix&quot;">​</a></h2><p>All four surfaces route through the same tools and the same policy gate. They differ in (1) which subset of tools they expose, (2) where confirmations happen, and (3) what host runtime they need. The matrix below describes the architected capabilities of each surface; the OpenClaw + Telegram column reflects the design for the OpenClaw skill (the Telegram bot itself is live, the broader OpenClaw skill is in development), and the Hosted Checkout column is in development.</p><table tabindex="0"><thead><tr><th>Capability</th><th>HavenBot</th><th>MCP</th><th>OpenClaw + Telegram</th><th>Hosted Checkout</th></tr></thead><tbody><tr><td>Sign in with passkey</td><td>✅ Dashboard</td><td>✅ Device-flow + dashboard</td><td>✅ Telegram link → dashboard</td><td>✅ At checkout (first use)</td></tr><tr><td>Read portfolio</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Read yields</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Propose buy</td><td>✅</td><td>✅ (envelope only)</td><td>✅ (with tier-aware confirm)</td><td>✅ (sole purpose)</td></tr><tr><td>Propose claim</td><td>✅</td><td>✅ (envelope only)</td><td>✅</td><td>❌</td></tr><tr><td>Set tier / pause</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Issuer: distribute yield</td><td>✅</td><td>✅</td><td>⛔ (excluded from skill subset)</td><td>❌</td></tr><tr><td>Issuer: KYC add/remove</td><td>✅</td><td>✅</td><td>⛔</td><td>❌</td></tr><tr><td>Issuer: unpause new token</td><td>✅</td><td>✅</td><td>⛔</td><td>❌</td></tr><tr><td>Issuer: create checkout link</td><td>✅ (via HavenBot tool)</td><td>❌</td><td>❌</td><td>✅ (sole purpose; via HavenBot)</td></tr><tr><td>Audit log query</td><td>✅</td><td>✅</td><td>✅ (read)</td><td>❌</td></tr><tr><td>Read-only mode</td><td>❌</td><td>✅ <code>MUHAVEN_READ_ONLY=true</code></td><td>n/a (skill subset)</td><td>n/a</td></tr><tr><td>Bring your own LLM</td><td>❌ (Gemini today)</td><td>✅</td><td>n/a (no LLM at the bot edge)</td><td>n/a</td></tr></tbody></table><p>Legend: ✅ supported by design · ⛔ deliberately excluded · ❌ not applicable. (OpenClaw skill + Hosted Checkout are in development; the Telegram bot, HavenBot, and MCP are live.)</p><h2 id="confirmation-surface-differences" tabindex="-1">Confirmation surface differences <a class="header-anchor" href="#confirmation-surface-differences" aria-label="Permalink to &quot;Confirmation surface differences&quot;">​</a></h2><p>The single biggest practical difference is <strong>where you confirm</strong>:</p><ul><li><strong>HavenBot</strong> confirms in-modal in the same browser tab.</li><li><strong>MCP</strong> never auto-submits — it hands you an envelope and you confirm on the dashboard or in your host&#39;s UI (depending on host capability).</li><li><strong>OpenClaw + Telegram</strong> uses a <strong>three-tier classifier</strong> based on USD amount: <ul><li><strong>≤ $200</strong> → inline keyboard button right in the Telegram chat</li><li><strong>$200 – $5,000</strong> → Telegram Mini App + 6-digit OTP</li><li><strong>&gt; $5,000</strong> → deep-link out to a passkey signature on the dashboard</li></ul></li><li><strong>Hosted Checkout</strong> confirms with a passkey at <code>muhaven.app/pay/...</code> — the only surface designed for users who don&#39;t yet have a MuHaven account.</li></ul><p>See <a href="/openclaw/confirmation-tiers">Three confirmation tiers</a> for the Telegram classifier in detail.</p><h2 id="can-i-use-multiple-surfaces" tabindex="-1">Can I use multiple surfaces? <a class="header-anchor" href="#can-i-use-multiple-surfaces" aria-label="Permalink to &quot;Can I use multiple surfaces?&quot;">​</a></h2><p>Yes — and most users do. The four surfaces share <strong>one</strong> MuHaven wallet, <strong>one</strong> audit log, <strong>one</strong> tier setting, and <strong>one</strong> <code>/pause</code> kill-switch. Linking a new surface doesn&#39;t fork your identity or your state.</p><p>A common stack:</p><ul><li><strong>HavenBot</strong> for ad-hoc dashboard work.</li><li><strong><code>@muhaven/mcp</code></strong> in Claude Code for cross-surface multi-agent workflows (&quot;pull my portfolio + write a memo + email my CPA&quot;).</li><li><strong>OpenClaw + Telegram</strong> for one-tap actions on mobile.</li><li><strong>Hosted Checkout</strong> if you&#39;re an issuer.</li></ul><p>The shared substrate ensures that:</p><ul><li>Pausing on one surface pauses <em>all</em> surfaces (the on-chain validator is uninstalled).</li><li>A tier change on one surface applies everywhere.</li><li>Every action on every surface writes to the same audit log.</li></ul><h2 id="what-to-read-next" tabindex="-1">What to read next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to read next&quot;">​</a></h2><ul><li><a href="/havenbot/overview">HavenBot overview</a></li><li><a href="/mcp/overview">MCP overview</a></li><li><a href="/openclaw/overview">OpenClaw overview</a></li><li><a href="/checkout/overview">Hosted Checkout overview</a></li><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — the policy substrate that ties all four together</li></ul>`,22)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
